pub async fn get_users_by_ids(pool: &sqlx::PgPool, ids: &[i32]) -> Result<Vec<GetUsersByIdsRow>, sqlx::Error> {
    sqlx::query_as!(GetUsersByIdsRow, "SELECT id, name, email FROM users WHERE id = ANY($1)", ids)
        .fetch_all(pool)
        .await
}

